INSERT INTO public.messages (id, session_id, sender_type, message_text, created_at) VALUES
(1, 1, 'YOUTH', 'I don''t really know how to say this but I haven''t been okay', '2026-06-14 07:00:00'),
(2, 1, 'WORKER', 'Thank you for telling me, Jun Wei. I want to understand better - can you share what''s been happening?', '2026-06-14 07:08:20'),
(3, 1, 'YOUTH', 'I''ve been hurting myself when things get too much, not seriously but it''s been happening more', '2026-06-14 07:16:40'),
(4, 1, 'WORKER', 'I''m really glad you told me this. Your safety matters a lot to me, and I''m going to make sure you get the right support.', '2026-06-14 07:25:00'),
(5, 2, 'YOUTH', 'hi! just wanted to share - my dance group practiced a new routine today', '2026-05-30 10:00:00'),
(6, 2, 'WORKER', 'That''s great to hear, Ahmad Danial! Glad things are going well. Keep it up :)', '2026-05-30 10:12:00'),
(7, 3, 'YOUTH', 'hi, can I talk for a bit? I''ve been feeling anxious about exams', '2026-06-10 07:00:00'),
(8, 3, 'WORKER', 'Of course, I''m here. Tell me more about what''s been going on.', '2026-06-10 07:18:00'),
(9, 4, 'YOUTH', 'hi! just wanted to share - I tried out a new digital art technique today', '2026-06-02 09:00:00'),
(10, 4, 'WORKER', 'That''s great to hear, Dinesh! Glad things are going well. Keep it up :)', '2026-06-02 09:12:00'),
(11, 5, 'YOUTH', 'hi! just wanted to share - I baked something with my sister over the weekend', '2026-06-08 08:00:00'),
(12, 5, 'WORKER', 'That''s great to hear, Yu Xuan! Glad things are going well. Keep it up :)', '2026-06-08 08:12:00'),
(13, 6, 'YOUTH', 'hi, can I talk for a bit? things at home have been tense lately', '2026-06-04 09:00:00'),
(14, 6, 'WORKER', 'Of course, I''m here. Tell me more about what''s been going on.', '2026-06-04 09:18:00'),
(15, 7, 'YOUTH', 'hi! just wanted to share - I finished a new drawing I''ve been working on', '2026-06-09 09:00:00'),
(16, 7, 'WORKER', 'That''s great to hear, Hui Min! Glad things are going well. Keep it up :)', '2026-06-09 09:12:00'),
(17, 8, 'YOUTH', 'hi, can I talk for a bit? I''ve been feeling anxious about exams', '2026-06-13 10:00:00'),
(18, 8, 'WORKER', 'Of course, I''m here. Tell me more about what''s been going on.', '2026-06-13 10:18:00'),
(19, 9, 'YOUTH', 'i dont think i want to be here anymore', '2026-06-15 00:00:00'),
(20, 9, 'AI', 'I''m really glad you reached out, Nurul Huda, and I''m taking what you said seriously. Are you safe right now?', '2026-06-15 00:03:36'),
(21, 9, 'YOUTH', 'i dont know. i just feel like everything is too much', '2026-06-15 00:07:12'),
(22, 9, 'AI', 'That sounds incredibly heavy to carry. I''m going to let your care team know right away so a real person can follow up with you soon. In the meantime, is there someone nearby you trust who can stay with you tonight?', '2026-06-15 00:10:48'),
(23, 9, 'YOUTH', 'maybe my sister, she''s home', '2026-06-15 00:14:24'),
(24, 9, 'AI', 'That''s good - please reach out to her now. Your worker will follow up with you as soon as possible.', '2026-06-15 00:18:00'),
(25, 10, 'YOUTH', 'hi', '2026-06-15 16:18:00'),
(26, 10, 'WORKER', 'Hi Nurul Huda, I heard about last night and wanted to check in with you myself. How are you feeling right now?', '2026-06-15 16:40:00'),
(27, 11, 'YOUTH', 'hi! just wanted to share - my dance group practiced a new routine today', '2026-06-08 06:00:00'),
(28, 11, 'WORKER', 'That''s great to hear, Yu Xuan! Glad things are going well. Keep it up :)', '2026-06-08 06:12:00'),
(29, 12, 'YOUTH', 'School has been really overwhelming this week and I''ve been arguing with my mum again.', '2026-06-22 10:00:00'),
(30, 12, 'WORKER', 'Thanks for being direct about it, Jun Wei. Let''s break down what has been feeling most intense first.', '2026-06-22 10:12:00'),
(31, 13, 'YOUTH', 'Things at home are still tense, but drawing has helped me calm down a bit.', '2026-06-23 14:00:00'),
(32, 13, 'WORKER', 'That''s useful to know. Let''s keep using drawing as a coping support while we plan your next family follow-up.', '2026-06-23 14:24:00'),
(33, 14, 'YOUTH', 'I still feel stressed, but it''s not as bad as last week and my sister has been checking on me.', '2026-06-24 16:00:00'),
(34, 14, 'WORKER', 'That''s a meaningful improvement. We''ll keep the safety plan active and stay in close contact this week.', '2026-06-24 16:36:00'),
(35, 15, 'YOUTH',  'Hi, things have been okay at school this week. Basketball tryouts went well.',                           '2026-06-24 10:00:00'),
(36, 15, 'WORKER', 'That''s great to hear, Ethan! Making the team would be a big confidence boost. Let''s keep that momentum going.', '2026-06-24 10:20:00'),
(37, 16, 'YOUTH',  'I wrote a poem about how I''ve been feeling. It helped a lot actually.',                                '2026-06-23 11:00:00'),
(38, 16, 'WORKER', 'I''m really glad journaling is working for you, Maya. Would you be open to sharing it with me next session?', '2026-06-23 11:18:00'),
(39, 17, 'YOUTH',  'I skipped school again on Monday. I don''t know how to explain it — I just couldn''t get out of bed.',   '2026-06-25 09:00:00'),
(40, 17, 'WORKER', 'Thank you for being honest about that, Zach. Can you tell me a bit more about what Monday morning felt like?', '2026-06-25 09:22:00'),
(41, 18, 'YOUTH',  'The basketball tryouts didn''t go the way I hoped. I''m alright though.',                                '2026-06-22 14:00:00'),
(42, 18, 'WORKER', 'That''s disappointing, but I respect how you''re handling it. What helped you stay steady today?',        '2026-06-22 14:15:00'),
(43, 19, 'YOUTH',  'My mum and I had a big argument last night. I left the house for a few hours.',                           '2026-06-25 15:00:00'),
(44, 19, 'WORKER', 'I''m glad you came back and that you''re here today. Let''s talk through what happened and how we can plan for next time.', '2026-06-25 15:20:00'),
(45, 20, 'YOUTH',  'Things are rough. My dad hasn''t come home in three days and my mum won''t talk about it.',              '2026-06-24 09:30:00'),
(46, 20, 'WORKER', 'That sounds like a lot of uncertainty to sit with. You''re not alone in this — let''s figure out what support looks like right now.', '2026-06-24 09:50:00');
INSERT INTO public.ai_summaries (id, session_id, summary_text, created_at) VALUES
(1, 1, 'Jun Wei disclosed self-harm behaviour during session. CW acknowledged disclosure and flagged for escalation and safety planning.', '2026-06-14 07:29:00'),
(2, 2, 'Ahmad Danial shared a positive update about K-pop dance. No concerns raised; rapport remains good.', '2026-05-30 10:14:00'),
(3, 3, 'Siti Zulaikha disclosed ongoing stress. CW provided supportive listening; recommend monitoring over next few sessions.', '2026-06-10 07:23:00'),
(4, 4, 'Dinesh shared a positive update about digital art. No concerns raised; rapport remains good.', '2026-06-02 09:14:00'),
(5, 5, 'Yu Xuan shared a positive update about baking. No concerns raised; rapport remains good.', '2026-06-08 08:13:00'),
(6, 6, 'Yu Xuan disclosed ongoing stress. CW provided supportive listening; recommend monitoring over next few sessions.', '2026-06-04 09:23:00'),
(7, 7, 'Hui Min shared a positive update about art and drawing. No concerns raised; rapport remains good.', '2026-06-09 09:15:00'),
(8, 8, 'Arun disclosed ongoing stress. CW provided supportive listening; recommend monitoring over next few sessions.', '2026-06-13 10:22:00'),
(9, 9, 'Nurul Huda expressed passive suicidal ideation during an after-hours chat. AI acknowledged the disclosure, conducted a brief safety check, identified a trusted person (sibling) present at home, and flagged the case for immediate care team follow-up.', '2026-06-15 00:20:00'),
(10, 10, 'Follow-up check-in after last night''s crisis disclosure. Nurul Huda engaged with CW; continued monitoring recommended.', '2026-06-15 16:44:00'),
(11, 11, 'Yu Xuan shared a positive update about K-pop dance. No concerns raised; rapport remains good.', '2026-06-08 06:14:00'),
(12, 12, 'Jun Wei reported school and family stress. Worker prioritized de-escalation, stress mapping, and a follow-up check-in later this week.', '2026-06-22 10:31:00'),
(13, 13, 'Ong Yu Xuan described continued family tension but identified drawing as a stabilising coping tool. Worker recommended ongoing monitoring and caregiver follow-up.', '2026-06-23 14:28:00'),
(14, 14, 'Nurul Huda reported modest improvement after crisis follow-up, with sibling support acting as a protective factor. Safety plan remains active.', '2026-06-24 16:41:00'),
(15, 15, 'Ethan Chen shared a positive update about basketball tryouts. Engagement is strong and no concerns were raised.', '2026-06-24 10:22:00'),
(16, 16, 'Maya Ravi described using poetry as an emotional outlet. CW encouraged continued use and proposed sharing in next session.', '2026-06-23 11:20:00'),
(17, 17, 'Zach Tan disclosed school avoidance. CW explored emotional and environmental barriers; follow-up with school counsellor recommended.', '2026-06-25 09:25:00'),
(18, 18, 'Ethan Chen reported missing basketball tryout expectations but maintained emotional stability. CW validated resilience.', '2026-06-22 14:17:00'),
(19, 19, 'Maya Ravi disclosed a significant family conflict involving leaving home. CW discussed safety and de-escalation strategies.', '2026-06-25 15:22:00'),
(20, 20, 'Zach Tan reported paternal absence over multiple days and maternal withdrawal. Significant family instability noted.', '2026-06-24 09:52:00');
